import "@/App.css";
import { lazy, Suspense } from "react";
import { BrowserRouter, Routes, Route } from "react-router-dom";
import { Toaster } from "sonner";

import { AuthProvider } from "./context/AuthContext";
import HomePage from "./pages/HomePage";
import LoginPage from "./pages/LoginPage";
import ProtectedRoute from "./components/admin/ProtectedRoute";

const AdminLayout = lazy(() => import("./components/admin/AdminLayout"));
const Overview = lazy(() => import("./pages/admin/Overview"));
const GalleryAdmin = lazy(() => import("./pages/admin/GalleryAdmin"));
const ReviewsAdmin = lazy(() => import("./pages/admin/ReviewsAdmin"));
const MessagesAdmin = lazy(() => import("./pages/admin/MessagesAdmin"));

export default function App() {
  return (
    <div className="App">
      <AuthProvider>
        <BrowserRouter>
          <Routes>
            <Route path="/" element={<HomePage />} />
            <Route path="/admin/login" element={<LoginPage />} />
            <Route
              path="/admin"
              element={
                <ProtectedRoute>
                  <Suspense>
                    <AdminLayout />
                  </Suspense>
                </ProtectedRoute>
              }
            >
              <Route index element={<Overview />} />
              <Route path="galerie" element={<GalleryAdmin />} />
              <Route path="recenzii" element={<ReviewsAdmin />} />
              <Route path="mesaje" element={<MessagesAdmin />} />
            </Route>
          </Routes>
        </BrowserRouter>
        <Toaster position="top-right" richColors closeButton />
      </AuthProvider>
    </div>
  );
}
